input.command:
node -e "
const {hexToBigInt} = require('/home/user/sandbox/workspace/frontend/node_modules/viem');
// API returns value as decimal string: '995010715204139091' (wei)
// hexToBigInt treats it as hex:
const wrongValue = hexToBigInt('995010715204139091');
console.log('Wrong (hex interpretation):', wrongValue.toString());
console.log('Wrong in ETH:', (Number(wrongValue) / 1e18).toFixed(6));

// Correct: parse as decimal BigInt
const correctValue = BigInt('995010715204139091');
console.log('Correct (decimal):', correctValue.toString());
console.log('Correct in ETH:', (Number(correctValue) / 1e18).toFixed(6));

// The SDK's own code: hexToBigInt(stepData.value || 0)
// If value is '0x...' hex string - works correctly
// If value is decimal string - WRONG
console.log('Is the API value hex?', '995010715204139091'.startsWith('0x'));
"

